class Solution:
    def intersectionSizeTwo(self, intervals: List[List[int]]) -> int:
        intervals.sort(key=lambda x: x[1])
        ans = []
        for s, e in intervals:
            have = [x for x in ans if s <= x <= e]
            if len(have) >= 2: continue
            if not have:
                ans.extend([e-1, e])
            elif len(have) == 1:
                ans.append(e if have[0] != e else e-1)
        return len(set(ans))

