int intersectionSizeTwo(int** intervals, int n, int* cs) {
    int ans[2000], an=0;
    for(int i=0;i<n;i++){
        int s=intervals[i][0], e=intervals[i][1], cnt=0;
        for(int j=0;j<an;j++) if(s<=ans[j]&&ans[j]<=e) cnt++;
        if(cnt>=2) continue;
        if(cnt==0){ ans[an++]=e-1; ans[an++]=e; }
        else ans[an++]=(ans[an-1]==e?e-1:e);
    }
    return an;
}
